			}
		);
		goto(`/${domain}/${pathSegment}/${childId}`);
	}

	async function deleteChild(domain: string, pathSegment: string, childId: string) {
		try {
			await apiDelete(`/api/${domain}/${pathSegment}/${childId}`);
			toast.success(m.common_child_deleted());
			await loadChildren();
		} catch (e) {
			toast.error(m.common_delete_failed({ error: (e as Error).message }));
		}
	}

	onMount(() => {
		loadChildren();
	});





	async function handleTransition(targetState: string) {
		transitioning = true;
		try {

			const ws = await transitionCandidate(item.id, targetState);

			item.workflow_state = {
				current_state: ws.current_state,
				is_terminal: ws.is_terminal,
				available_transitions: ws.available_transitions,
			};
			toast.success(m.common_transitioned_to({ state: targetState }));
		} catch (e) {
			toast.error(m.common_transition_failed({ error: (e as Error).message }));
		} finally {
